import "./UserTable.css";
import { Tag, Spin, Pagination } from "antd";
import { EditOutlined, DeleteOutlined } from "@ant-design/icons";
import { useEffect, useState, useMemo } from "react";
import { getProvinces } from "../../../../../api/axios/Auth/authApi";

export default function UserTable({
  onRowClick,
  onEdit,
  onDelete, 
  loading,
  users = [],
}) {

  const [provinces, setProvinces] = useState([]);

  /* PAGINATION */
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 7;

  /* ================= FETCH PROVINCES ================= */
  useEffect(() => {
    fetchProvinces();
  }, []);

  const fetchProvinces = async () => {
    try {
      const res = await getProvinces();
      const data = res?.data || res || [];
      setProvinces(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("FETCH PROVINCES ERROR:", error);
      setProvinces([]);
    }
  };

  /* ================= PROVINCE MAP ================= */
  const provinceMap = useMemo(() => {
    const map = {};
    provinces.forEach((p) => {
      map[Number(p.id)] = p.name;
    });
    return map;
  }, [provinces]);

  /* ================= PAGINATED USERS ================= */

  const paginatedUsers = useMemo(() => {

    const start = (currentPage - 1) * pageSize;
    const end = start + pageSize;

    return users.slice(start, end);

  }, [users, currentPage]);

  /* ================= ROLE COLOR ================= */

  const getRoleColor = (role) => {
    if (!role) return "default";

    switch (role.toLowerCase()) {
      case "admin":
        return "red";
      case "manager":
        return "gold";
      case "coordinator":
        return "purple";
      case "rescueteam":
        return "blue";
      default:
        return "default";
    }
  };

  /* ================= STATUS COLOR ================= */

  const getStatusColor = (status) => {
    if (!status) return "default";

    switch (status.toLowerCase()) {
      case "hoạt động":
        return "green";
      case "khóa":
        return "red";
      default:
        return "default";
    }
  };

  return (

    <div className="userTable">

      {loading ? (

        <div className="userTable__loading">
          <Spin size="large" />
        </div>

      ) : (

        <>

          <table>

            <thead>
              <tr>
                <th style={{ width: "60px" }}>STT</th>
                <th>Người dùng</th>
                <th>Số điện thoại</th>
                <th>Vai trò</th>
                <th>Khu vực</th>
                <th>Trạng thái</th>
                <th style={{ width: "120px" }}>Hành động</th>
              </tr>
            </thead>

            <tbody>

              {paginatedUsers.length === 0 ? (

                <tr>
                  <td colSpan="7" className="userTable__empty">
                    Không có dữ liệu
                  </td>
                </tr>

              ) : (

                paginatedUsers.map((user, index) => (

                  <tr
                    key={user.id}
                    onClick={() => onRowClick?.(user)}
                  >

                    {/* STT */}
                    <td className="userTable__stt">
                      {(currentPage - 1) * pageSize + index + 1}
                    </td>

                    {/* NAME */}
                    <td>
                      <div className="userTable__name">
                        {user.name || "N/A"}
                      </div>
                    </td>

                    {/* PHONE */}
                    <td>
                      {user.phone || "N/A"}
                    </td>

                    {/* ROLE */}
                    <td>
                      <Tag color={getRoleColor(user.role)}>
                        {user.role || "N/A"}
                      </Tag>
                    </td>

                    {/* AREA */}
                    <td>
                      {provinceMap[Number(user.areaId)] || "Chưa Cập Nhật"}
                    </td>

                    {/* STATUS */}
                    <td>
                      <Tag color={getStatusColor(user.status)}>
                        {user.status || "N/A"}
                      </Tag>
                    </td>

                    {/* EDIT */}
                    <td className="userTable__actions">

  <EditOutlined
    onClick={(e) => {
      e.stopPropagation();
      onEdit?.(user);
    }}
    style={{ cursor: "pointer", marginRight: 12, color: "#1677ff" }}
  />

<DeleteOutlined
  onClick={(e) => {
    e.stopPropagation();
    onDelete?.(user);
  }}
  style={{
    cursor: "pointer",
    color: "#ff4d4f",
    fontSize: 18
  }}
/>

</td>

                  </tr>

                ))

              )}

            </tbody>

          </table>

          {/* PAGINATION UI */}

          {users.length > pageSize && (

            <div className="userTable__pagination">

              <Pagination
                current={currentPage}
                pageSize={pageSize}
                total={users.length}
                onChange={(page) => setCurrentPage(page)}
                showSizeChanger={false}
              />

            </div>

          )}

        </>

      )}

    </div>

  );
}

import React, { useEffect, useState } from "react";
import { Timeline, Tag, Spin, Empty, Card } from "antd";
import { HistoryOutlined, CheckCircleOutlined, SyncOutlined, ClockCircleOutlined } from "@ant-design/icons";
import { getAllRequestLogs } from "../../../../api/axios/RescueRequests/rescueRequestsApi";

/**
 * Reusable component to display the audit log / action history of a rescue request.
 * @param {Object} props
 * @param {number|string} props.rescueRequestId - The ID of the rescue request to fetch logs for.
 * @param {string} [props.title="Lịch sử Hoạt động"] - Optional title for the header.
 */
const MissionHistory = ({ rescueRequestId, title = "Lịch sử Hoạt động" }) => {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(false);

  const fetchLogs = async () => {
    if (!rescueRequestId) return;
    try {
      setLoading(true);
      const data = await getAllRequestLogs(rescueRequestId);
      setLogs(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Error fetching mission history:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLogs();
  }, [rescueRequestId]);

  const getTimelineIcon = (action) => {
    const act = action?.toLowerCase() || "";
    if (act.includes("hoàn thành") || act.includes("complete")) return <CheckCircleOutlined style={{ color: "#52c41a" }} />;
    if (act.includes("đang") || act.includes("process")) return <SyncOutlined spin style={{ color: "#1890ff" }} />;
    if (act.includes("tạo") || act.includes("create")) return <HistoryOutlined style={{ color: "#8c8c8c" }} />;
    return <ClockCircleOutlined style={{ color: "#faad14" }} />;
  };

  return (
    <Card 
      title={<><HistoryOutlined /> {title}</>} 
      className="mission-history-card"
      style={{ marginTop: 16, borderRadius: 12 }}
    >
      <Spin spinning={loading}>
        {logs.length > 0 ? (
          <Timeline
            mode="left"
            items={logs.map((log) => ({
              label: log.createdAt ? new Date(log.createdAt).toLocaleString("vi-VN", {
                hour: '2-digit',
                minute: '2-digit',
                day: '2-digit',
                month: '2-digit'
              }) : "N/A",
              children: (
                <div className="log-item">
                  <div style={{ fontWeight: 600, color: "#262626" }}>{log.action}</div>
                  <div style={{ fontSize: "12px", color: "#8c8c8c" }}>
                    Người thực hiện: <Tag color="default" style={{ fontSize: "10px" }}>User {log.performedBy}</Tag>
                  </div>
                </div>
              ),
              dot: getTimelineIcon(log.action),
            }))}
          />
        ) : (
          <Empty description="Chưa có lịch sử hoạt động" image={Empty.PRESENTED_IMAGE_SIMPLE} />
        )}
      </Spin>
    </Card>
  );
};

export default MissionHistory;

'use client';

import {
  Modal,
  Form,
  Input,
  Button,
  Select
} from 'antd';

import {
  UserOutlined,
  PhoneOutlined
} from '@ant-design/icons';

import { useState, useEffect } from 'react';

import {
  createTeamMember
} from '../../../../../../api/axios/ManagerApi/rescueTeamApi';

import { getAllUser } from '../../../../../../api/axios/AdminApi/userApi';

import AuthNotify from '../../../../../utils/Common/AuthNotify';

import "./CreateMemberModal.css";

const { Option } = Select;

export default function CreateMemberModal({
  open,
  onClose,
  teamId,
  onSuccess,
  memberCount,
  members
}) {

  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [users, setUsers] = useState([]);
  const [loadingUsers, setLoadingUsers] = useState(false);

  /* ================= LOAD USERS ================= */

  useEffect(() => {

    if (open) {
      fetchData();
    }

  }, [open, members]);


  const fetchData = async () => {

    try {

      setLoadingUsers(true);

      const allUsersRes = await getAllUser();

      let allUsers = [];

      /* normalize API */

      if (Array.isArray(allUsersRes)) {
        allUsers = allUsersRes;
      }
      else if (Array.isArray(allUsersRes?.data)) {
        allUsers = allUsersRes.data;
      }
      else if (Array.isArray(allUsersRes?.items)) {
        allUsers = allUsersRes.items;
      }

      /* user đã trong team */

      const existingUserIds = new Set(
        (members || []).map(m => String(m.userId))
      );

      /* chỉ lấy role RescueTeam */

      const filteredUsers = allUsers.filter(user => {

        const userId = String(user.userId);

        if (user.roleName !== "RescueTeam") return false;

        if (existingUserIds.has(userId)) return false;

        return true;

      });

      setUsers(filteredUsers);

    }
    catch (err) {

      console.log(err);

      AuthNotify.error(
        "Không thể tải dữ liệu",
        "Vui lòng thử lại sau"
      );

    }
    finally {

      setLoadingUsers(false);

    }

  };


  /* ================= AUTO FILL ================= */

  const handleUserChange = (userId) => {

    const selectedUser = users.find(
      u => Number(u.userId) === Number(userId)
    );

    if (!selectedUser) return;

    form.setFieldsValue({

      fullName: selectedUser.fullName || selectedUser.name || "",
      phone: selectedUser.phone || "",
      roleInTeam: selectedUser.roleName || "RescueTeam"

    });

  };


  /* ================= CREATE ================= */

  const handleCreate = async () => {

    if (memberCount >= 5) {

      AuthNotify.error(
        "Không thể thêm thành viên",
        "Mỗi đội chỉ được tối đa 5 thành viên"
      );

      return;

    }

    if (users.length === 0) {

      AuthNotify.error(
        "Không có user khả dụng",
        "Không còn RescueTeam nào chưa thuộc đội"
      );

      return;

    }

    try {

      const values = await form.validateFields();

      setLoading(true);

      const payload = {

        rescueTeamId: teamId,
        userId: Number(values.userId),
        fullName: String(values.fullName),
        phone: String(values.phone),
        roleInTeam: String(values.roleInTeam || "RescueTeam")

      };

      await createTeamMember(teamId, payload);

      AuthNotify.success(
        "Tạo thành viên thành công",
        "Thành viên đã được thêm vào đội"
      );

      await fetchData();

      form.resetFields();

      onClose();

      onSuccess?.();

    }
    catch (error) {

      console.log(error);

      AuthNotify.error(
        "Tạo thành viên thất bại",
        "Không thể thêm thành viên"
      );

    }
    finally {

      setLoading(false);

    }

  };


  /* ================= UI ================= */

  return (

    <Modal
      open={open}
      title="➕ Tạo thành viên đội cứu hộ"
      onCancel={onClose}
      footer={null}
      width={500}
      className="create-member-modal"
      centered
    >

      <Form
        form={form}
        layout="vertical"
        className="create-member-form"
      >

        {/* USER */}

        <Form.Item
          name="userId"
          label="Chọn User"
          rules={[
            { required: true, message: "Chọn user" }
          ]}
        >

          <Select
            size="large"
            placeholder={
              users.length === 0
                ? "Không có RescueTeam khả dụng"
                : "Chọn RescueTeam"
            }
            loading={loadingUsers}
            showSearch
            onChange={handleUserChange}
            optionFilterProp="children"
          >

            {users.map(user => (

              <Option
                key={user.userId}
                value={user.userId}
              >
                {user.userId} - {user.fullName || user.name} ({user.roleName})
              </Option>

            ))}

          </Select>

        </Form.Item>


        {/* NAME */}

        <Form.Item
          name="fullName"
          label="Họ và tên"
        >

          <Input
            prefix={<UserOutlined />}
            size="large"
            disabled
          />

        </Form.Item>


        {/* PHONE */}

        <Form.Item
          name="phone"
          label="Số điện thoại"
        >

          <Input
            prefix={<PhoneOutlined />}
            size="large"
            disabled
          />

        </Form.Item>


        {/* ROLE */}

        <Form.Item
          name="roleInTeam"
          label="Vai trò trong đội"
        >

          <Input
            prefix={<UserOutlined />}
            size="large"
            disabled
          />

        </Form.Item>


        {memberCount >= 5 && (
          <p style={{color:"#ef4444", marginBottom:10}}>
            Đội đã đạt tối đa 5 thành viên
          </p>
        )}


        <Button
          type="primary"
          block
          size="large"
          loading={loading}
          onClick={handleCreate}
          disabled={memberCount >= 5}
          className="create-member-btn"
        >
          Tạo thành viên
        </Button>

      </Form>

    </Modal>

  );

}

'use client';

import {
  Modal,
  Form,
  Input,
  Select,
  Button
} from 'antd';

import {
  SafetyOutlined,
  PhoneOutlined,
  EnvironmentOutlined
} from '@ant-design/icons';

import {
  createRescueTeam
} from '../../../../../../api/axios/ManagerApi/rescueTeamApi';

import { getProvinces } from '../../../../../../api/axios/Auth/authApi';

import { useState, useEffect } from 'react';

import AuthNotify from "../../../../../utils/Common/AuthNotify";

import './CreateTeamModal.css';

const { Option } = Select;

/* ================= PHONE VALIDATOR ================= */

const validateVietnamPhone = (_, value) => {

  if (!value) {
    return Promise.reject("Vui lòng nhập số điện thoại");
  }

  const phoneRegex = /^0\d{9}$/;

  if (!phoneRegex.test(value)) {
    return Promise.reject(
      "Số điện thoại phải gồm 10 số và bắt đầu bằng 0 (VD: 0901234567)"
    );
  }

  return Promise.resolve();

};

export default function CreateTeamModal({
  open,
  onClose,
  onSuccess
}) {

  const [form] = Form.useForm();

  const [loading, setLoading] = useState(false);

  const [provinces, setProvinces] = useState([]);

  /* ================= LOAD PROVINCES ================= */

  useEffect(() => {

    if (open) {
      fetchProvinces();

      form.setFieldsValue({
        rcStatus: "on duty"
      });

    }

  }, [open]);

  const fetchProvinces = async () => {

    try {

      const res = await getProvinces();

      const data = res?.data || res || [];

      setProvinces(
        Array.isArray(data) ? data : []
      );

    }
    catch (error) {

      console.error(error);

      AuthNotify.error(
        "Không tải được khu vực",
        "Vui lòng thử lại"
      );

    }

  };

  /* ================= CREATE TEAM ================= */

  const handleCreate = async () => {

    try {

      const values = await form.validateFields();

      setLoading(true);

      await createRescueTeam({

        rcName: values.rcName,
        rcPhone: values.rcPhone,
        areaId: Number(values.areaId),

        /* STATUS MẶC ĐỊNH */

        rcStatus: "on duty"

      });

      AuthNotify.success(
        "Tạo đội cứu hộ thành công",
        "Đội cứu hộ mới đã được tạo"
      );

      form.resetFields();

      onClose?.();

      onSuccess?.();

    }
    catch (error) {

      console.error(error);

      AuthNotify.error(
        "Tạo đội thất bại",
        "Không thể tạo đội cứu hộ"
      );

    }
    finally {

      setLoading(false);

    }

  };

  /* ================= UI ================= */

  return (

    <Modal
      open={open}
      title="🚑 Tạo đội cứu hộ mới"
      onCancel={onClose}
      footer={null}
      width={520}
      className="createTeamModal"
    >

      <Form
        form={form}
        layout="vertical"
      >

        {/* TEAM NAME */}

        <Form.Item
          name="rcName"
          label="Tên đội cứu hộ"
          rules={[
            {
              required: true,
              message: "Nhập tên đội"
            }
          ]}
        >

          <Input
            prefix={<SafetyOutlined />}
            placeholder="VD: Đội cứu hộ Quận 1"
            size="large"
          />

        </Form.Item>


        {/* PHONE */}

        <Form.Item
          name="rcPhone"
          label="Số điện thoại"
          validateTrigger="onChange"
          rules={[
            { validator: validateVietnamPhone }
          ]}
        >

          <Input
            prefix={<PhoneOutlined />}
            placeholder="0901234567"
            size="large"
            maxLength={10}
            onChange={(e) => {

              const onlyNumber =
                e.target.value.replace(/\D/g, "");

              form.setFieldsValue({
                rcPhone: onlyNumber
              });

            }}
          />

        </Form.Item>


        {/* AREA */}

        <Form.Item
          name="areaId"
          label="Khu vực"
          rules={[
            {
              required: true,
              message: "Chọn khu vực"
            }
          ]}
        >

          <Select
            size="large"
            placeholder="Chọn khu vực"
            suffixIcon={<EnvironmentOutlined />}
            options={provinces.map((item) => ({
              label: item.name,
              value: item.id
            }))}
          />

        </Form.Item>


        {/* BUTTON */}

        <Button
          type="primary"
          block
          size="large"
          loading={loading}
          onClick={handleCreate}
          className="createTeamModal__btn"
        >

          🚑 Tạo đội cứu hộ

        </Button>

      </Form>

    </Modal>

  );

}

'use client';

import React, { useEffect, useState } from "react";

import {
  Modal,
  Form,
  Input,
  Select,
  Button
} from "antd";

import {
  updateRescueTeam
} from "../../../../../api/axios/ManagerApi/rescueTeamApi";

import {
  getProvinces
} from "../../../../../api/axios/Auth/authApi";

import AuthNotify from "../../../../utils/Common/AuthNotify";

import "./EditTeamModal.css";

const { Option } = Select;

export default function EditTeamModal({
  open,
  onClose,
  team,
  onSuccess
}) {

  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [provinces, setProvinces] = useState([]);

  /* ================= LOAD PROVINCES ================= */

  useEffect(() => {

    if (open) {
      fetchProvinces();
    }

  }, [open]);


  const fetchProvinces = async () => {

    try {

      const res = await getProvinces();

      const data = res?.data || res || [];

      setProvinces(
        Array.isArray(data) ? data : []
      );

    }
    catch (error) {

      console.log("Load provinces error:", error);

      AuthNotify.error(
        "Không tải được khu vực",
        "Vui lòng thử lại"
      );

    }

  };


  /* ================= LOAD TEAM DATA ================= */

  useEffect(() => {

    if (!team) return;

    form.setFieldsValue({
      rcName: team.name,
      rcPhone: team.phone,
      areaId: team.areaId
    });

  }, [team]);


  /* ================= UPDATE TEAM ================= */

  const handleUpdate = async () => {

    try {

      const values = await form.validateFields();

      setLoading(true);

      await updateRescueTeam(team.id, {

        rcName: values.rcName,
        rcPhone: values.rcPhone,
        areaId: Number(values.areaId)

      });

      AuthNotify.success(
        "Cập nhật thành công",
        "Thông tin đội cứu hộ đã được cập nhật"
      );

      form.resetFields();

      onClose?.();

      onSuccess?.();

    }
    catch (error) {

      console.log(error);

      AuthNotify.error(
        "Cập nhật thất bại",
        "Không thể cập nhật đội cứu hộ"
      );

    }
    finally {

      setLoading(false);

    }

  };


  /* ================= UI ================= */

  return (

    <Modal
      open={open}
      title="✏️ Chỉnh sửa đội cứu hộ"
      onCancel={onClose}
      footer={null}
      width={520}
      centered
      destroyOnClose
      className="editTeamModal"
    >

      <Form
        form={form}
        layout="vertical"
      >

        {/* TEAM NAME */}

        <Form.Item
          name="rcName"
          label="Tên đội cứu hộ"
          rules={[
            {
              required: true,
              message: "Nhập tên đội"
            }
          ]}
        >

          <Input
            placeholder="VD: Đội cứu hộ Quận 1"
            size="large"
          />

        </Form.Item>


        {/* PHONE */}

        <Form.Item
          name="rcPhone"
          label="Số điện thoại"
          rules={[
            {
              required: true,
              message: "Nhập số điện thoại"
            }
          ]}
        >

          <Input
            placeholder="0901234567"
            size="large"
            maxLength={10}
            onChange={(e) => {

              const onlyNumber =
                e.target.value.replace(/\D/g, "");

              form.setFieldsValue({
                rcPhone: onlyNumber
              });

            }}
          />

        </Form.Item>


        {/* AREA */}

        <Form.Item
          name="areaId"
          label="Khu vực"
          rules={[
            {
              required: true,
