import { useEffect, useMemo, useState } from "react";
import { Button, Checkbox, Input, message, Space, Tabs } from "antd";
import "./Permissions.css";

const ROLES = ["admin", "manager", "coordinator", "rescue"];

const FEATURES = [
  { id: "dispatch", name: "Điều phối / Phân công", actions: ["view", "assign", "update", "delete"] },
  { id: "reports", name: "Báo cáo", actions: ["view", "export"] },
  { id: "inventory", name: "Kho hàng", actions: ["view", "update", "deduct"] },
  { id: "requests", name: "Yêu cầu cứu hộ", actions: ["create", "view", "update", "close"] },
  { id: "settings", name: "Cấu hình hệ thống", actions: ["view", "update"] },
  { id: "logs", name: "Logs hệ thống", actions: ["view", "clear"] },
];

function readRoleMatrix() {
  try {
    const raw = localStorage.getItem("system_configs");
    const parsed = raw ? JSON.parse(raw) : [];
    const item = (parsed || []).find((c) => c.key === "ROLE_PERMISSION_MATRIX");
    if (item && typeof item.value === "object") return item.value;
  } catch (e) {
    // ignore
  }
  // default empty matrix
  const mat = {};
  ROLES.forEach((r) => {
    mat[r] = {};
    FEATURES.forEach((f) => (mat[r][f.id] = []));
  });
  return mat;
}

function saveRoleMatrix(matrix) {
  try {
    const raw = localStorage.getItem("system_configs");
    const configs = raw ? JSON.parse(raw) : [];
    const idx = configs.findIndex((c) => c.key === "ROLE_PERMISSION_MATRIX");
    if (idx >= 0) configs[idx].value = matrix;
    else configs.push({ key: "ROLE_PERMISSION_MATRIX", name: "ROLE_PERMISSION_MATRIX – Ma trận quyền", type: "json", value: matrix, group: "permission" });
    localStorage.setItem("system_configs", JSON.stringify(configs));
  } catch (e) {
    throw e;
  }
}

function pushLog(entry) {
  try {
    const raw = localStorage.getItem("system_logs");
    const arr = raw ? JSON.parse(raw) : [];
    arr.unshift(entry);
    localStorage.setItem("system_logs", JSON.stringify(arr));
  } catch (e) {
    // ignore
  }
}

export default function Permissions() {
  const [matrix, setMatrix] = useState(() => readRoleMatrix());
  const [username, setUsername] = useState("");
  const [activeRole, setActiveRole] = useState("admin");
  const [userOverrides, setUserOverrides] = useState(() => {
    try {
      const raw = localStorage.getItem("user_permissions");
      return raw ? JSON.parse(raw) : {};
    } catch (e) {
      return {};
    }
  });

  useEffect(() => {
    // ensure matrix is loaded
    setMatrix(readRoleMatrix());
  }, []);

  const handleToggle = (role, featureId, action, checked) => {
    setMatrix((prev) => {
      const copy = { ...prev };
      copy[role] = { ...copy[role] };
      const arr = new Set(copy[role][featureId] || []);
      if (checked) arr.add(action);
      else arr.delete(action);
      copy[role][featureId] = Array.from(arr);
      return copy;
    });
  };

  const handleSaveMatrix = () => {
    try {
      saveRoleMatrix(matrix);
      const actor = localStorage.getItem("role") || "system";
      pushLog({ id: Date.now(), time: new Date().toISOString(), level: "INFO", user: actor, message: `Cập nhật ma trận quyền` });
      message.success("Lưu ma trận quyền thành công");
    } catch (e) {
      message.error("Lưu thất bại");
    }
  };

  const handleSaveUserOverride = () => {
    if (!username) return message.error("Nhập username để lưu override");
    const newOverrides = { ...userOverrides, [username]: matrix };
    setUserOverrides(newOverrides);
    localStorage.setItem("user_permissions", JSON.stringify(newOverrides));
    const actor = localStorage.getItem("role") || "system";
    pushLog({ id: Date.now(), time: new Date().toISOString(), level: "INFO", user: actor, message: `Gán quyền đặc biệt cho user=${username}` });
    message.success("Lưu override cho user thành công");
  };

  const handleLoadUser = () => {
    if (!username) return message.error("Nhập username để load override");
    const u = userOverrides[username];
    if (u) setMatrix(u);
    else message.info("Không tìm thấy override cho user này");
  };

  const featureRows = useMemo(() => FEATURES, []);

  const tabItems = ROLES.map((role) => ({
    key: role,
    label: role.charAt(0).toUpperCase() + role.slice(1),
    children: (
      <div className="role-permissions">
        <div className="permissions-list">
          {featureRows.map((feature) => (
            <div key={feature.id} className="permission-item">
              <div className="permission-header">
                <div className="permission-label">
                  <h4>{feature.name}</h4>
                  <p className="permission-feature-id">{feature.id}</p>
                </div>
              </div>
              <div className="permission-actions">
                <div className="actions-row">
                  {feature.actions.map((action) => {
                    const checked = (matrix[role] && matrix[role][feature.id] || []).includes(action);
                    return (
                      <label className="action-item" key={action}>
                        <Checkbox
                          checked={checked}
                          onChange={(e) => handleToggle(role, feature.id, action, e.target.checked)}
                        />
                        <span className="action-label">{action}</span>
                      </label>
                    );
                  })}
                </div>
              </div>
              <div className="permission-action">
                <Button
                  type="text"
                  size="small"
                  onClick={handleSaveMatrix}
                  className="save-btn"
                >
                  Lưu
                </Button>
              </div>
            </div>
          ))}
        </div>
      </div>
    ),
  }));

  return (
    <div className="permissions-page">
      <div className="page-header">
        <div>
          <h2>Quản lý Phân quyền</h2>
          <p>Cấu hình chi tiết quyền hạn theo role, chức năng và hành động</p>
        </div>
      </div>

      <div className="permissions-container">
        <div className="user-override-section">
          <div className="override-header">
            <h3>Quyền đặc biệt cho User</h3>
            <div className="override-actions">
              <Space>
                <Input
                  placeholder="Nhập username"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  style={{ width: 200 }}
                />
                <Button onClick={handleLoadUser}>Tải quyền</Button>
                <Button onClick={handleSaveUserOverride} type="default">
                  Lưu đặc biệt
                </Button>
              </Space>
            </div>
          </div>
        </div>

        <div className="matrix-box">
          <Tabs
            activeKey={activeRole}
            onChange={setActiveRole}
            items={tabItems}
            className="permissions-tabs"
          />
        </div>
      </div>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Button, Input, Switch, message, Tabs, Table, Modal, Form, Popconfirm, Space, Card, Spin } from "antd";
import { SaveOutlined, ReloadOutlined, PlusOutlined, SettingOutlined, WarningOutlined } from "@ant-design/icons";
import {
  getAllSystemConfigurations,
  updateSystemConfiguration,
  seedSystemConfigurations
} from "../../../../api/axios/SystemConfigurations/systemConfigurationsApi";
import {
  getAllUrgencyLevels,
  createUrgencyLevel,
  updateUrgencyLevel,
  deleteUrgencyLevel,
  getAllRequestLogs
} from "../../../../api/axios/RescueRequests/rescueRequestsApi";
import "./SystemSetting.css";

export default function SystemSetting() {
  const [configs, setConfigs] = useState([]);
  const [urgencyLevels, setUrgencyLevels] = useState([]);
  const [requestLogs, setRequestLogs] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activeMainTab, setActiveMainTab] = useState("system");
  const [activeConfigTab, setActiveConfigTab] = useState("");

  // Request Log Filter State
  const [logRequestId, setLogRequestId] = useState("");

  // Urgency Level Modal State
  const [isUrgencyModalVisible, setIsUrgencyModalVisible] = useState(false);
  const [editingUrgency, setEditingUrgency] = useState(null);

  const fetchConfigs = async () => {
    try {
      setLoading(true);
      const data = await getAllSystemConfigurations();
      setConfigs(data || []);
      if (data && data.length > 0 && !activeConfigTab) {
        setActiveConfigTab(data[0].configGroup);
      }
    } catch (error) {
      console.error("Fetch configs failed:", error);
      message.error("Không thể tải cấu hình hệ thống");
    } finally {
      setLoading(false);
    }
  };

  const fetchUrgencyLevels = async () => {
    try {
      setLoading(true);
      const data = await getAllUrgencyLevels();
      setUrgencyLevels(data || []);
    } catch (error) {
      console.error("Fetch urgency levels failed:", error);
      message.error("Không thể tải danh sách cấp độ khẩn cấp");
    } finally {
      setLoading(false);
    }
  };

  const fetchRequestLogs = async (id = "") => {
    try {
      setLoading(true);
      const data = await getAllRequestLogs(id || null);
      setRequestLogs(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Fetch request logs failed:", error);
      message.error("Không thể tải nhật ký yêu cầu");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchConfigs();
    fetchUrgencyLevels();
    fetchRequestLogs();
  }, []);

  const handleUpdateConfig = async (configKey, configValue, configGroup, description) => {
    try {
      setLoading(true);
      await updateSystemConfiguration(configKey, {
        configKey,
        configValue,
        configGroup,
        description,
      });
      message.success(`Đã cập nhật: ${configKey}`);
      fetchConfigs();
    } catch (error) {
      message.error(`Cập nhật thất bại: ${configKey}`);
    } finally {
      setLoading(false);
    }
  };

  const handleSeed = async () => {
    try {
      setLoading(true);
      await seedSystemConfigurations();
      message.success("Đã nạp cấu hình mặc định");
      fetchConfigs();
    } catch (e) {
      message.error("Nạp cấu hình mặc định thất bại");
    } finally {
      setLoading(false);
    }
  };

  const handleUrgencySubmit = async (values) => {
    try {
      setLoading(true);
      if (editingUrgency) {
        await updateUrgencyLevel(editingUrgency.id, values);
        message.success("Cập nhật cấp độ khẩn cấp thành công");
      } else {
        await createUrgencyLevel(values);
        message.success("Tạo mới cấp độ khẩn cấp thành công");
      }
      setIsUrgencyModalVisible(false);
      setEditingUrgency(null);
      fetchUrgencyLevels();
    } catch (error) {
      message.error("Thao tác thất bại");
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteUrgency = async (id) => {
    try {
      setLoading(true);
      await deleteUrgencyLevel(id);
      message.success("Xóa cấp độ khẩn cấp thành công");
      fetchUrgencyLevels();
    } catch (error) {
      message.error("Xóa thất bại");
    } finally {
      setLoading(false);
    }
  };

  const configGroups = useMemo(() => {
    const groups = [...new Set(configs.map((c) => c.configGroup))];
    return groups.sort();
  }, [configs]);

  const urgencyColumns = [
    { title: "Tên cấp độ", dataIndex: "levelName", key: "levelName", width: "25%" },
    { title: "Mô tả", dataIndex: "description", key: "description", width: "45%" },
    { title: "SLA (Phút)", dataIndex: "slaMinutes", key: "slaMinutes", width: "15%" },
    {
      title: "Thao tác",
      key: "action",
      width: "15%",
      render: (_, record) => (
        <Space size="middle">
          <Button 
            type="link" 
            onClick={() => {
              setEditingUrgency(record);
              setIsUrgencyModalVisible(true);
            }}
          >
            Sửa
          </Button>
          <Popconfirm
            title="Xóa cấp độ này?"
            description="Bạn có chắc chắn muốn xóa cấp độ khẩn cấp này không?"
            onConfirm={() => handleDeleteUrgency(record.id)}
            okText="Xóa"
            cancelText="Hủy"
          >
            <Button type="link" danger>Xóa</Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  const renderConfigField = (config) => {
    const val = config.configValue;
    const isBoolean = val === "true" || val === "false";

    if (isBoolean) {
      return (
        <Switch 
          checked={val === "true"} 
          onChange={(checked) => handleUpdateConfig(config.configKey, String(checked), config.configGroup, config.description)}
          loading={loading}
        />
      );
    }

    return (
      <Input.Search
        defaultValue={val}
        enterButton={<SaveOutlined />}
        onSearch={(value) => handleUpdateConfig(config.configKey, value, config.configGroup, config.description)}
        loading={loading}
      />
    );
  };

  const mainTabs = [
    {
      key: "system",
      label: (
        <span>
          <SettingOutlined /> Cấu hình Hệ thống
        </span>
      ),
      children: (
        <div className="system-config-container">
          {configGroups.length > 0 ? (
            <Tabs
              tabPosition="left"
              activeKey={activeConfigTab}
              onChange={setActiveConfigTab}
              className="config-sub-tabs"
              items={configGroups.map((group) => ({
                key: group,
                label: group.toUpperCase(),
                children: (
                  <div className="config-group-content">
                    <Card title={`Nhóm: ${group.toUpperCase()}`} variant="borderless">
                      {configs
                        .filter((c) => c.configGroup === group)
                        .map((config) => (
                          <div key={config.configKey} className="config-item">
                            <div className="config-info">
                              <h4>{config.description || config.configKey}</h4>
                              <code>{config.configKey}</code>
                            </div>
                            <div className="config-input">
                              {renderConfigField(config)}
                            </div>
                          </div>
                        ))}
                    </Card>
                  </div>
                ),
              }))}
            />
          ) : (
            <div className="empty-state" style={{ textAlign: "center", padding: "40px" }}>
              <Spin spinning={loading}>
                {!loading && (
                  <>
                    <p>Không có dữ liệu cấu hình. Vui lòng nạp mặc định hoặc kiểm tra kết nối.</p>
                    <Button type="primary" onClick={handleSeed}>Nạp Cấu hình Mặc định</Button>
                  </>
                )}
              </Spin>
            </div>
          )}
        </div>
      ),
    },
    {
      key: "urgency",
      label: (
        <span>
          <WarningOutlined /> Cấp độ Khẩn cấp
        </span>
      ),
      children: (
        <div className="urgency-management">
          <Card 
            title="Danh sách Cấp độ Khẩn cấp" 
            extra={
              <Button type="primary" icon={<PlusOutlined />} onClick={() => { setEditingUrgency(null); setIsUrgencyModalVisible(true); }}>
                Thêm Cấp độ
              </Button>
            }
          >
            <Table 
              dataSource={urgencyLevels} 
              columns={urgencyColumns} 
              rowKey="id" 
              loading={loading}
              pagination={false}
            />
          </Card>
        </div>
      ),
    },
    {
      key: "logs",
      label: (
        <span>
          <ReloadOutlined /> Nhật ký Yêu cầu
        </span>
      ),
      children: (
        <div className="request-logs-container">
          <Card 
            title="Lịch sử Hoạt động Yêu cứu Cứu hộ" 
            extra={
              <Space>
                <Input 
                  placeholder="Mã yêu cầu (ID)" 
                  value={logRequestId} 
                  onChange={(e) => setLogRequestId(e.target.value)}
                  onPressEnter={() => fetchRequestLogs(logRequestId)}
                  size="small"
                  style={{ width: 150 }}
                />
                <Button 
                  icon={<ReloadOutlined />} 
                  onClick={() => fetchRequestLogs(logRequestId)}
                  loading={loading}
                  size="small"
                >
                  Làm mới
                </Button>
              </Space>
            }
          >
            <Table 
              dataSource={requestLogs} 
              columns={[
                { title: "ID", dataIndex: "id", key: "id", width: 80 },
                { 
                  title: "REQ ID", 
                  dataIndex: "rescueRequestId", 
                  key: "rescueRequestId", 
                  width: 100,
                  render: (id) => <Tag color="blue">REQ-{id}</Tag>
                },
                { title: "Hành động", dataIndex: "action", key: "action" },
                { title: "Người thực hiện", dataIndex: "performedBy", key: "performedBy", render: (u) => `User ${u}` },
                { title: "Thời gian", dataIndex: "createdAt", key: "createdAt", render: (t) => t ? new Date(t).toLocaleString() : "N/A" },
              ]} 
              rowKey="id" 
              loading={loading}
              pagination={{ pageSize: 8 }}
            />
          </Card>
        </div>
      ),
    },
  ];

  return (
    <div className="system-setting-page">
      <div className="page-header">
        <div>
          <h2>Quản trị Hệ thống</h2>
          <p>Quản lý các thông số vận hành và cấp độ khẩn cấp toàn hệ thống</p>
        </div>
        <div className="header-actions">
          <Button icon={<ReloadOutlined />} onClick={() => { fetchConfigs(); fetchUrgencyLevels(); }} loading={loading}>
            Làm mới
          </Button>
          <Popconfirm
            title="Nạp lại cấu hình mặc định?"
            description="Tất cả thay đổi hiện tại sẽ bị xóa và ghi đè bằng giá trị mặc định."
            onConfirm={handleSeed}
            okText="Xác nhận"
            cancelText="Hủy"
          >
            <Button danger icon={<ReloadOutlined />}>Nạp Mặc định</Button>
          </Popconfirm>
        </div>
      </div>

      <div className="main-tabs-container">
        <Tabs
          activeKey={activeMainTab}
          onChange={setActiveMainTab}
          items={mainTabs}
          type="card"
          className="premium-tabs"
        />
      </div>

      <Modal
        title={editingUrgency ? "Chỉnh sửa Cấp độ" : "Thêm Cấp độ Mới"}
        open={isUrgencyModalVisible}
        onCancel={() => { setIsUrgencyModalVisible(false); setEditingUrgency(null); }}
        footer={null}
        destroyOnClose
      >
        <Form
          initialValues={editingUrgency || { levelName: "", description: "", slaMinutes: 30 }}
          onFinish={handleUrgencySubmit}
          layout="vertical"
        >
          <Form.Item name="levelName" label="Tên cấp độ" rules={[{ required: true }]}>
            <Input placeholder="Ví dụ: Cấp độ 1" />
          </Form.Item>
          <Form.Item name="description" label="Mô tả" rules={[{ required: true }]}>
            <Input.TextArea rows={3} />
          </Form.Item>
          <Form.Item name="slaMinutes" label="SLA (Phút)" rules={[{ required: true }]}>
            <Input type="number" min={1} />
          </Form.Item>
          <div className="modal-footer" style={{ display: "flex", justifyContent: "flex-end", gap: "10px", marginTop: "20px" }}>
            <Button onClick={() => setIsUrgencyModalVisible(false)}>Hủy</Button>
            <Button type="primary" htmlType="submit" loading={loading}>
              Lưu thay đổi
            </Button>
          </div>
        </Form>
      </Modal>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Button, Form, message, Modal} from "antd";
import {
  PlusOutlined
} from "@ant-design/icons";

import "./UserManagement.css";
import { ExclamationCircleOutlined } from "@ant-design/icons";
import UserTable from "../../../components/AdminComponents/TableUser/UserListManager/UserTable";
import UserFormModal from "../../../components/AdminComponents/TableUser/FormModal/UserFormModal";
import StatCard from "../../../components/AdminComponents/TableUser/FormModal/StatCard";
import AuthNotify from "../../../utils/Common/AuthNotify";
import {
  registerUser,
  getAllUser,
  deleteUser
} from "../../../../api/axios/AdminApi/userApi";
 import {updateUser} from "../../../../api/axios/Auth/authApi";

export default function UserManagement() {

  const [form] = Form.useForm();

  const [users, setUsers] = useState([]);

  const [loading, setLoading] = useState(false);

  const [modalOpen, setModalOpen] = useState(false);

