import { useEffect, useState } from "react";
import { Button, message } from "antd";

import {
  getInventoryTransactions,
  confirmInventoryTransaction,
} from "../../../../api/axios/ManagerApi/inventoryApi";

import "./ApprovalManagement.css";

export default function ApprovalDispatch() {
  const [transactions, setTransactions] = useState([]);
  const [filter, setFilter] = useState("pending");

  useEffect(() => {
    loadTransactions();
  }, []);

  const loadTransactions = async () => {
    try {
      const res = await getInventoryTransactions();

      const outTransactions = res.data
        .filter((t) => t.transactionType === "OUT")
        .map((t) => ({
          ...t,
          id: t.id || t.transactionId,
        }));

      setTransactions(outTransactions);
    } catch {
      message.error("Load transactions thất bại");
    }
  };

  /* ================= FILTER ================= */

  const pending = transactions.filter(
    (t) => !t.confirmedAt && !t.confirmed_at
  );

  const confirmed = transactions.filter(
    (t) => t.confirmedAt || t.confirmed_at
  );

  const displayData = filter === "pending" ? pending : confirmed;

  /* ================= CONFIRM ================= */

  const handleConfirm = async (id) => {
    try {
      await confirmInventoryTransaction(id);

      message.success("Dispatch thành công");

      loadTransactions();
    } catch {
      message.error("Confirm thất bại");
    }
  };

  return (
    <div className="dispatch-page">
      {/* ================= TABLE ================= */}

      <div className="dispatch-table">

        <div className="table-header">
          <h3>Dispatch Approval</h3>

          <div className="filter">
            <Button
              type={filter === "pending" ? "primary" : "default"}
              onClick={() => setFilter("pending")}
            >
              Pending ({pending.length})
            </Button>

            <Button
              type={filter === "confirmed" ? "primary" : "default"}
              onClick={() => setFilter("confirmed")}
            >
              Confirmed ({confirmed.length})
            </Button>
          </div>
        </div>

        {/* ================= TABLE HEAD ================= */}

        <div className="table-head">
          <span>Transaction</span>
          <span>Warehouse</span>
          <span>Type</span>
          <span>Items</span>
          <span>Status</span>
          <span>Action</span>
        </div>

        {/* ================= ROW ================= */}

        {displayData.map((t) => (
          <div className="table-row" key={t.id}>
            <div className="row-cell">
              <strong>#{t.id}</strong>
              <p>Request: {t.rescueRequestId}</p>
            </div>

            <div className="row-cell">
              <strong>{t.warehouseId}</strong>
            </div>

            <div className="row-cell">
              <strong>{t.transactionType}</strong>
            </div>

            <div className="row-cell item">
              <div>
                {t.lines?.map((l, i) => (
                  <p key={i}>
                    Item {l.reliefItemId} - Qty: {l.quantity}
                  </p>
                ))}
              </div>
            </div>

            <div className="row-cell">
              {t.confirmedAt || t.confirmed_at ? (
                <strong style={{ color: "#22c55e" }}>Confirmed</strong>
              ) : (
                <strong style={{ color: "#f97316" }}>Pending</strong>
              )}
            </div>

            <div className="row-cell actions">
              {!t.confirmedAt && !t.confirmed_at && (
                <Button
                  type="primary"
                  onClick={() => handleConfirm(t.id)}
                >
                  Confirm
                </Button>
              )}
            </div>
          </div>
        ))}

        {/* ================= FOOTER ================= */}

        <div className="table-footer">
          <span>Total: {displayData.length}</span>
        </div>

      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import {
  Button,
  Drawer,
  Form,
  Input,
  InputNumber,
  Select,
  Table,
  Space,
  Tabs,
  message,
  Card,
  Row,
  Col
} from "antd";

import {
  getAllWarehouses,
  createWarehouse,
  updateWarehouse,
  deleteWarehouse,
  getAllReliefItems,
  createReliefItem,
  updateReliefItem,
  deleteReliefItem,
  getInventoryTransactions,
  createInventoryTransaction,
  confirmInventoryTransaction,
  getWarehouseInventory,
} from "../../../../api/axios/ManagerApi/inventoryApi";

import "./InventoryManagement.css";

export default function InventoryManagement() {

  const [warehouses, setWarehouses] = useState([]);
  const [items, setItems] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [inventory, setInventory] = useState([]);

  const [selectedWarehouseId, setSelectedWarehouseId] = useState(null);
  const [activeTab, setActiveTab] = useState("");

  const [warehouseDrawer, setWarehouseDrawer] = useState(false);
  const [itemDrawer, setItemDrawer] = useState(false);
  const [transactionDrawer, setTransactionDrawer] = useState(false);

  const [editingWarehouse, setEditingWarehouse] = useState(null);
  const [editingItem, setEditingItem] = useState(null);

  const [form] = Form.useForm();
  const [itemForm] = Form.useForm();
  const [transactionForm] = Form.useForm();

  useEffect(() => {
    loadAll();
  }, []);

  /* ================= LOAD DATA ================= */

  const loadAll = async () => {
    try {

      const [w, i, t] = await Promise.all([
        getAllWarehouses(),
        getAllReliefItems(),
        getInventoryTransactions(),
      ]);

      const warehouseData = w.data.map((x) => ({
        ...x,
        id: x.id || x.warehouseId,
      }));

      setWarehouses(warehouseData);

      if (warehouseData.length > 0) {
        const firstId = warehouseData[0].id;
        setSelectedWarehouseId(firstId);
        setActiveTab(`warehouse-${firstId}`);
        handleSelectWarehouseInventory(firstId);
      }

      setItems(
        i.data.map((x) => ({
          ...x,
          id: x.id || x.reliefItemId,
        }))
      );

      setTransactions(
        t.data.map((x) => ({
          ...x,
          id: x.id || x.transactionId,
        }))
      );

    } catch {
      message.error("Load dữ liệu thất bại");
    }
  };

  /* ================= INVENTORY ================= */

  const handleSelectWarehouseInventory = async (warehouseId) => {

    setSelectedWarehouseId(warehouseId);
    setActiveTab(`warehouse-${warehouseId}`);

    try {

      const res = await getWarehouseInventory(warehouseId);

      setInventory(
        res.data.map((x, index) => ({
          key: index,
          itemName: x.itemName,
          quantity: x.quantity,
        }))
      );

    } catch {
      message.error("Load inventory thất bại");
    }
  };

  /* ================= TRANSACTION FILTER ================= */

  const inTransactions = transactions.filter(
    (t) => t.transactionType === "IN"
  );

  const pendingTransactions = inTransactions.filter(
    (t) => !t.confirmedAt && !t.confirmed_at
  );

  const confirmedTransactions = inTransactions.filter(
    (t) => t.confirmedAt || t.confirmed_at
  );

  /* ================= WAREHOUSE ================= */

  const handleSaveWarehouse = async (values) => {

    try {

      if (editingWarehouse) {
        await updateWarehouse(editingWarehouse.id, values);
      } else {
        await createWarehouse(values);
      }

      message.success("Lưu warehouse thành công");

      setWarehouseDrawer(false);
      setEditingWarehouse(null);
      form.resetFields();
      loadAll();

    } catch {
      message.error("Lưu warehouse thất bại");
    }
  };

  const handleDeleteWarehouse = async (id) => {

    try {

      await deleteWarehouse(id);
      message.success("Xoá kho thành công");
      loadAll();

    } catch (err) {

      if (err.response?.status === 409) {
        message.error("Kho đang còn vật phẩm");
      } else {
        message.error("Xoá kho thất bại");
      }
    }
  };

  /* ================= ITEM ================= */

  const handleSaveItem = async (values) => {

    try {

      if (editingItem) {
        await updateReliefItem(editingItem.id, values);
      } else {
        await createReliefItem(values);
      }

      message.success("Lưu item thành công");

      setItemDrawer(false);
      setEditingItem(null);
      itemForm.resetFields();
      loadAll();

    } catch {
      message.error("Lưu item thất bại");
    }
  };

  const handleDeleteItem = async (id) => {

    try {
      await deleteReliefItem(id);
      message.success("Xoá item thành công");
      loadAll();
    } catch {
      message.error("Xoá item thất bại");
    }
  };

  /* ================= TRANSACTION ================= */

  const handleCreateTransaction = async (values) => {

    try {

      await createInventoryTransaction(values);

      message.success("Tạo transaction thành công");

      setTransactionDrawer(false);
      transactionForm.resetFields();
      loadAll();

    } catch {
      message.error("Tạo transaction thất bại");
    }
  };

  const handleConfirmTransaction = async (id) => {

    try {

      await confirmInventoryTransaction(id);

      message.success("Confirm thành công");

      loadAll();

      if (selectedWarehouseId) {
        handleSelectWarehouseInventory(selectedWarehouseId);
      }

    } catch {
      message.error("Confirm thất bại");
    }
  };

  /* ================= TABLE COLUMNS ================= */

  const warehouseColumns = [
    { title: "ID", dataIndex: "id" },
    { title: "Name", dataIndex: "warehouseName" },
    { title: "Location", dataIndex: "locationDescription" },
    {
      title: "Action",
      render: (_, record) => (
        <Space>

          <Button
            onClick={() => {
              setEditingWarehouse(record);
              form.setFieldsValue(record);
              setWarehouseDrawer(true);
            }}
          >
            Edit
          </Button>

          <Button
            danger
            onClick={() => handleDeleteWarehouse(record.id)}
          >
            Delete
          </Button>

        </Space>
      ),
    },
  ];

  const itemColumns = [
    { title: "ID", dataIndex: "id" },
    { title: "Name", dataIndex: "itemName" },
    { title: "Unit", dataIndex: "unit" },
    {
      title: "Action",
      render: (_, record) => (
        <Space>

          <Button
            onClick={() => {
              setEditingItem(record);
              itemForm.setFieldsValue(record);
              setItemDrawer(true);
            }}
          >
            Edit
          </Button>

          <Button
            danger
            onClick={() => handleDeleteItem(record.id)}
          >
            Delete
          </Button>

        </Space>
      ),
    },
  ];

  const transactionColumns = [
    { title: "ID", dataIndex: "id" },
    { title: "Warehouse", dataIndex: "warehouseId" },
    { title: "Type", dataIndex: "transactionType" },
    {
      title: "Action",
      render: (_, record) =>
        record.confirmedAt || record.confirmed_at ? (
          <span style={{ color: "green", fontWeight: "bold" }}>
            Confirmed
          </span>
        ) : (
          <Button
            type="primary"
            onClick={() => handleConfirmTransaction(record.id)}
          >
            Confirm
          </Button>
        ),
    },
  ];

  /* ================= WAREHOUSE INVENTORY TABS ================= */

  const warehouseTabs = warehouses.map((w) => ({
    key: `warehouse-${w.id}`,
    label: w.warehouseName,
    children: (
      <div className="inventory-card">

        <Row gutter={[16, 16]}>
  {inventory.map((item) => (
    <Col xs={24} sm={12} md={8} lg={6} key={item.key}>
      <Card className="inventory-item-card" hoverable>

        <h3>{item.itemName}</h3>

        <p className="inventory-quantity">
          {item.quantity}
        </p>

        <span className="inventory-label">
          Available
        </span>

      </Card>
    </Col>
  ))}
</Row>

      </div>
    ),
  }));

  /* ================= UI ================= */

  return (
    <div className="inventory-page">

      <div className="inventory-header">

        <div className="inventory-title">
          <h2>📦 Inventory Management</h2>
          <p>Quản lý kho cứu trợ</p>
        </div>

        <Space>

          <Select
            style={{ width: 220 }}
            value={selectedWarehouseId}
            placeholder="Chọn kho"
            options={warehouses.map((w) => ({
              value: w.id,
              label: w.warehouseName,
            }))}
            onChange={handleSelectWarehouseInventory}
          />

          <Button
            type="primary"
            onClick={() => {
              setEditingWarehouse(null);
              form.resetFields();
              setWarehouseDrawer(true);
            }}
          >
            Thêm kho
          </Button>

          <Button onClick={() => setActiveTab("warehouses")}>
            Warehouses
          </Button>

          <Button onClick={() => setActiveTab("items")}>
            Relief Items
          </Button>

          <Button
            type="primary"
            onClick={() => setActiveTab("transactions")}
          >
            Giao dịch
          </Button>

        </Space>
      </div>

      <Tabs
  activeKey={activeTab}
  renderTabBar={() => null}   // ẨN THANH TAB
  onChange={(key) => {

    setActiveTab(key);

    if (key.startsWith("warehouse-")) {
      const id = key.split("-")[1];
      handleSelectWarehouseInventory(id);
    }
  }}
  items={[

          ...warehouseTabs,

          {
            key: "warehouses",
            label: "Warehouses",
            children: (
              <div className="inventory-card">
                <Table
                  rowKey="id"
                  columns={warehouseColumns}
                  dataSource={warehouses}
                />
              </div>
            ),
          },

          {
            key: "items",
            label: "Relief Items",
            children: (
              <div className="inventory-card">

                <Button
                  type="primary"
                  style={{ marginBottom: 16 }}
                  onClick={() => setItemDrawer(true)}
                >
                  Add Item
                </Button>

                <Table
                  rowKey="id"
                  columns={itemColumns}
                  dataSource={items}
                />

              </div>
            ),
          },

          {
            key: "transactions",
            label: "Giao dịch",
            children: (
              <div className="inventory-card">

                <Tabs
                  items={[
                    {
                      key: "pending",
                      label: `Pending (${pendingTransactions.length})`,
                      children: (
                        <Table
                          rowKey="id"
                          columns={transactionColumns}
                          dataSource={pendingTransactions}
                        />
                      ),
                    },
                    {
                      key: "confirmed",
                      label: `Confirmed (${confirmedTransactions.length})`,
                      children: (
                        <Table
                          rowKey="id"
                          columns={transactionColumns}
                          dataSource={confirmedTransactions}
                        />
                      ),
                    },
                  ]}
                />

              </div>
            ),
          },
        ]}
      />

      {/* DRAWER WAREHOUSE */}

      <Drawer
        title={editingWarehouse ? "Edit Warehouse" : "Add Warehouse"}
        open={warehouseDrawer}
        onClose={() => setWarehouseDrawer(false)}
        width={420}
      >

        <Form form={form} layout="vertical" onFinish={handleSaveWarehouse}>

          <Form.Item
            label="Warehouse Name"
            name="warehouseName"
            rules={[{ required: true }]}
          >
            <Input />
          </Form.Item>

          <Form.Item
            label="Location Description"
            name="locationDescription"
            rules={[{ required: true }]}
          >
            <Input />
          </Form.Item>

          <Form.Item
            label="Area ID"
            name="areaId"
            rules={[{ required: true }]}
          >
            <InputNumber style={{ width: "100%" }} />
          </Form.Item>

          <Button type="primary" htmlType="submit" block>
            {editingWarehouse ? "Update" : "Create"}
          </Button>

        </Form>

      </Drawer>

      {/* DRAWER ITEM */}

      <Drawer
        title={editingItem ? "Edit Item" : "Add Item"}
        open={itemDrawer}
        onClose={() => setItemDrawer(false)}
        width={420}
      >

        <Form form={itemForm} layout="vertical" onFinish={handleSaveItem}>

          <Form.Item
            label="Item Name"
            name="itemName"
            rules={[{ required: true }]}
          >
            <Input />
          </Form.Item>

          <Form.Item
            label="Unit"
            name="unit"
            rules={[{ required: true }]}
          >
            <Input />
          </Form.Item>

          <Button type="primary" htmlType="submit" block>
            {editingItem ? "Update" : "Create"}
          </Button>

        </Form>

      </Drawer>

    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Button, Spin, message } from 'antd';
import {
  FilterOutlined,
  DownloadOutlined,
  TeamOutlined,
  ThunderboltOutlined,
  CoffeeOutlined,
  UserOutlined,
} from '@ant-design/icons';
import TeamManagementList from '../../../components/ManagerComponents/rescue-team/TeamTable/TeamManagementList';
import ScheduleList from '../../../components/ManagerComponents/rescue-team/TeamSchedule/ScheduleList';
import { getAllRescueTeams } from '../../../../api/axios/ManagerApi/rescueTeamApi'; // ← import hàm api
import './RescueTeamManagement.css';

export default function RescueTeamManagement() {
  const [teams, setTeams] = useState([]);
  const [filterStatus, setFilterStatus] = useState('all');
  const [loading, setLoading] = useState(true);
  const fetchTeams = async () => {
    try {
      setLoading(true);

      const response = await getAllRescueTeams();
      const data = response.data;

      if (Array.isArray(data)) {
        setTeams(data);
      } else if (Array.isArray(data?.data)) {
        setTeams(data.data);
      } else if (Array.isArray(data?.items)) {
        setTeams(data.items);
      } else {
        setTeams([]);
      }

    } catch (error) {
      message.error("Không thể tải danh sách đội");
    } finally {
      setLoading(false);
    }
  };
  const normalizeStatus = (status) => {
    if (!status) return "unknown";

    const s = status.toLowerCase().trim();

    if (s === "on duty" || s === "active")
      return "active";

    if (s === "off duty" || s === "rest")
      return "rest";

    return "unknown";
  };
  useEffect(() => {
    fetchTeams();
  }, []);
  // Lọc đội theo trạng thái
  const getFilteredTeams = () => {
    if (filterStatus === 'all') return teams;

    return teams.filter((team) => {
      return normalizeStatus(team.rcStatus) === filterStatus;
    });
  };

  const getTeamCount = (status) => {
    if (status === 'all') return teams.length;

    return teams.filter(
      (team) => normalizeStatus(team.rcStatus) === status
    ).length;
  };

  const totalMembers = teams.reduce((sum, team) => sum + (team.members || 0), 0);

  const filteredTeams = getFilteredTeams();

  // Mapping dữ liệu API sang format component con mong đợi
  const mappedTeams = filteredTeams.map((team) => ({
    id: team.rcid,
    name: team.rcName || 'Chưa đặt tên',
    members: team.members || 0,
    status: normalizeStatus(team.rcStatus), 
    mission: team.mission || '—',
    phone: team.rcPhone || '—',
    teamMembers: [],
    areaId: Number(team.areaId),
  }));

  if (loading) {
    return (
      <div className="rescue-page" style={{ minHeight: '60vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Spin size="large" tip="Đang tải danh sách đội cứu hộ..." />
      </div>
    );
  }

  return (
    <div className="rescue-page">
      <div className="page-header">
        <div>
          <h2>Quản lý Đội cứu hộ</h2>
          <p>Giám sát và sắp xếp nhân sự cho các đội cứu hộ dưới quyền (UC-M08, UC-M18)</p>
        </div>

        <div className="header-actions">
          <Button icon={<FilterOutlined />}>Lọc nâng cao</Button>
          <Button icon={<DownloadOutlined />}>Xuất báo cáo</Button>
        </div>
      </div>

      <div className="stat-grid">
        <div onClick={() => setFilterStatus('all')} style={{ cursor: 'pointer' }}>
          <StatCard
            title="TỔNG SỐ ĐỘI"
            value={getTeamCount('all')}
            icon={<TeamOutlined />}
            active={filterStatus === 'all'}
          />
        </div>
        <div onClick={() => setFilterStatus('active')} style={{ cursor: 'pointer' }}>
          <StatCard
            title="Sẵng Sàng"
            value={getTeamCount('active')}
            icon={<ThunderboltOutlined />}
            green
            active={filterStatus === 'active'}
          />
        </div>
        <div onClick={() => setFilterStatus('rest')} style={{ cursor: 'pointer' }}>
          <StatCard
            title="ĐANG NGHỈ"
            value={getTeamCount('rest')}
            icon={<CoffeeOutlined />}
            gray
            active={filterStatus === 'rest'}
          />
        </div>
        {/* <StatCard
          title="NHÂN SỰ SẴN SÀNG"
          value={totalMembers}
          icon={<UserOutlined />}
        /> */}
      </div>

 <TeamManagementList
  teamsData={mappedTeams}
  filterStatus={filterStatus}
  onTeamChanged={fetchTeams}
/>
      <ScheduleList />
    </div>
  );
}

function StatCard({ title, value, icon, green, gray, active }) {
  return (
    <div className={`stat-card ${green ? 'green' : ''} ${gray ? 'gray' : ''} ${active ? 'active' : ''}`}>
      <div className="stat-icon">{icon}</div>
      <span>{title}</span>
      <h2>{value}</h2>
    </div>
  );
}

import { useEffect, useState } from "react";
import {
  Button,
  Tag,
  Input,
  Progress,
  Modal,
  message,
  Card,
  Form,
  Select,
  Dropdown,
  Drawer,
  Pagination,
} from "antd";

import {
  ToolOutlined,
  StopOutlined,
  CheckCircleOutlined,
  MoreOutlined,
  SearchOutlined
} from "@ant-design/icons";

import {
  getAllVehicles,
  createVehicle,
  updateVehicle,
  deleteVehicle,
} from "../../../../api/axios/ManagerApi/vehicleApi";

import "./VehicleManagement.css";

export default function VehicleManagement() {

  const [vehicleList, setVehicleList] = useState([]);
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("all");
  const [filterType, setFilterType] = useState(null);

  const [modalVisible, setModalVisible] = useState(false);
  const [editingVehicle, setEditingVehicle] = useState(null);

  const [drawerVisible, setDrawerVisible] = useState(false);
  const [selectedVehicle, setSelectedVehicle] = useState(null);

  const [progressPercent, setProgressPercent] = useState(0);

  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 6;

  const [form] = Form.useForm();

  /* ================= LOAD ================= */

  const loadVehicles = async () => {
    try {
      const res = await getAllVehicles({ q: search });
      setVehicleList(res.data || []);
    } catch {
      message.error("Không tải được vehicles");
    }
  };

  useEffect(() => {
    loadVehicles();
  }, []);

  /* ================= SEARCH ================= */

  const handleSearch = () => {
    setCurrentPage(1);
    loadVehicles();
  };

  /* ================= CREATE ================= */

  const handleCreate = () => {
    setEditingVehicle(null);
    form.resetFields();
    setModalVisible(true);
  };

  const handleSubmit = async () => {
    try {
      const values = await form.validateFields();

      if (editingVehicle) {
        await updateVehicle(editingVehicle.id, values);
        message.success("Cập nhật vehicle thành công");
      } else {
        await createVehicle(values);
        message.success("Tạo vehicle thành công");
      }

      setModalVisible(false);
      loadVehicles();

    } catch {
      message.error("Lưu thất bại");
    }
  };

  /* ================= EDIT ================= */

  const handleEdit = (vehicle) => {
    setEditingVehicle(vehicle);
    form.setFieldsValue(vehicle);
    setModalVisible(true);
  };

  /* ================= DELETE ================= */

  const handleDelete = (vehicle) => {
    Modal.confirm({
      title: "Xóa vehicle?",
      content: vehicle.vehicleName,
      okType: "danger",
      async onOk() {
        await deleteVehicle(vehicle.id);
        message.success("Đã xóa");
        loadVehicles();
      },
    });
  };

  /* ================= STATUS ================= */

  const getStatusTag = (status) => {

    const map = {
      ready: { color: "green", text: "SẴN SÀNG" },
      maintenance: { color: "orange", text: "BẢO TRÌ" },
      stop: { color: "red", text: "DỪNG" },
      "ready-action": { color: "blue", text: "SẴN SÀNG HOẠT ĐỘNG" },
    };

    const data = map[status] || map.ready;

    return <Tag color={data.color}>{data.text}</Tag>;
  };

  /* ================= FILTER ================= */

  const filteredVehicles = vehicleList.filter((v) => {

    const matchStatus =
      filterStatus === "all" || v.vehicleStatus === filterStatus;

    const matchType =
      !filterType || v.vehicleType === filterType;

    const matchSearch =
      !search ||
      v.vehicleName?.toLowerCase().includes(search.toLowerCase()) ||
      v.plateNumber?.toLowerCase().includes(search.toLowerCase());

    return matchStatus && matchType && matchSearch;
  });

  /* ================= PAGINATION ================= */

  const startIndex = (currentPage - 1) * pageSize;
  const paginatedVehicles = filteredVehicles.slice(
    startIndex,
    startIndex + pageSize
  );

  /* ================= COUNT ================= */

  const count = (status) =>
    vehicleList.filter((v) => v.vehicleStatus === status).length;

  const total = vehicleList.length;
  const readyCount = count("ready");

  const realPercent = total ? Math.round((readyCount / total) * 100) : 0;

  /* ================= PROGRESS ================= */

  useEffect(() => {

    let i = 0;

    const interval = setInterval(() => {

      i += 1;

      if (i >= realPercent) {
        clearInterval(interval);
        setProgressPercent(realPercent);
      } else {
        setProgressPercent(i);
      }

    }, 10);

    return () => clearInterval(interval);

  }, [realPercent]);

  /* ================= ACTION MENU ================= */

  const actionMenu = (vehicle) => ({
    items: [
      {
        key: "edit",
        label: "Cập nhật",
        onClick: () => handleEdit(vehicle),
      },
      {
        key: "delete",
        label: "Xóa",
        danger: true,
        onClick: () => handleDelete(vehicle),
      },
    ],
  });

  /* ================= DRAWER ================= */

  const openDrawer = (vehicle) => {
    setSelectedVehicle(vehicle);
    setDrawerVisible(true);
  };

  /* ================= TYPE OPTIONS ================= */

  const typeOptions = [
    ...new Set(vehicleList.map(v => v.vehicleType))
  ].map(t => ({
    label: t,
    value: t
  }));

  /* ================================================= */

  return (
    <div className="vehicle-page">

      {/* PERFORMANCE */}

      <div className="vehicle-performance">

        <div className="performance-header">

          <div>
            <h3>Vehicle Performance</h3>
            <p>Total: {total}</p>
          </div>

          <span className="percentage">{progressPercent}%</span>

        </div>

        <Progress percent={progressPercent} showInfo={false} />

      </div>

      {/* SEARCH UI */}

      <div className="vehicle-search">

        <Input
          prefix={<SearchOutlined />}
          placeholder="Tìm theo tên hoặc biển số..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <Select
          placeholder="Loại xe"
          allowClear
          options={typeOptions}
          onChange={(v) => setFilterType(v)}
        />

        <Select
          placeholder="Trạng thái"
          allowClear
          onChange={(v) => setFilterStatus(v || "all")}
          options={[
            { value: "ready", label: "Sẵn sàng" },
            { value: "ready-action", label: "Ready Action" },
            { value: "maintenance", label: "Bảo trì" },
            { value: "stop", label: "Dừng" },
          ]}
        />

        <Button type="primary" onClick={handleSearch}>
          Tìm kiếm
        </Button>

        <Button onClick={handleCreate}>
          Thêm phương tiện
        </Button>

      </div>

      {/* CARD GRID */}

      <div className="vehicle-grid">

        {paginatedVehicles.map((v) => (

          <Card
            key={v.id}
            className="vehicle-card"
            hoverable
            onClick={() => openDrawer(v)}
          >

            <div className="vehicle-card-header">

              <h3>{v.vehicleName}</h3>

              <div onClick={(e) => e.stopPropagation()}>
                <Dropdown menu={actionMenu(v)} trigger={["click"]}>
                  <Button icon={<MoreOutlined />} />
                </Dropdown>
              </div>

            </div>

            <div className="vehicle-card-body">

              <p><b>Loại:</b> {v.vehicleType}</p>
              <p><b>Vị trí:</b> {v.vehicleLocation}</p>

              <div style={{ marginTop: 10 }}>
                {getStatusTag(v.vehicleStatus)}
              </div>

            </div>

          </Card>

        ))}

      </div>

      <Pagination
        style={{ marginTop: 20 }}
        current={currentPage}
        pageSize={pageSize}
        total={filteredVehicles.length}
        onChange={(page) => setCurrentPage(page)}
      />

      {/* MODAL */}

      <Modal
        title={editingVehicle ? "Cập nhật phương tiện" : "Thêm phương tiện"}
        open={modalVisible}
        onCancel={() => setModalVisible(false)}
        onOk={handleSubmit}
      >

        <Form form={form} layout="vertical">

          <Form.Item
            name="vehicleName"
            label="Tên phương tiện"
            rules={[{ required: true }]}
          >
            <Input />
          </Form.Item>

          <Form.Item
            name="vehicleType"
            label="Loại phương tiện"
            rules={[{ required: true }]}
          >
            <Input />
          </Form.Item>

          <Form.Item
            name="vehicleLocation"
            label="Vị trí"
          >
            <Input />
          </Form.Item>

          <Form.Item
            name="vehicleStatus"
            label="Trạng thái"
          >
            <Select
              options={[
                { value: "ready", label: "Sẵn sàng" },
                { value: "ready-action", label: "Ready Action" },
                { value: "maintenance", label: "Bảo trì" },
                { value: "stop", label: "Dừng" },
              ]}
            />
          </Form.Item>

        </Form>

      </Modal>

      {/* DRAWER */}

      <Drawer
        title="Chi tiết phương tiện"
        open={drawerVisible}
        onClose={() => setDrawerVisible(false)}
        width={400}
      >

        {selectedVehicle && (

          <div className="drawer-content">

            <p><b>Mã:</b> {selectedVehicle.id}</p>
            <p><b>Tên xe:</b> {selectedVehicle.vehicleName}</p>
            <p><b>Loại xe:</b> {selectedVehicle.vehicleType}</p>
            <p><b>Vị trí:</b> {selectedVehicle.vehicleLocation}</p>
            <p><b>Trạng thái:</b> {getStatusTag(selectedVehicle.vehicleStatus)}</p>

          </div>

        )}

      </Drawer>

    </div>
  );
}

